# Menger sponge-like fractal with holes only on one face direction
size = 90.0
levels = 3

def menger_holes(size, levels, origin=(0, 0, 0)):
    """Generate hole boxes for Menger sponge pattern, drilled through X axis."""
    holes = []

    def recurse(x, y, z, s, level):
        if level == 0:
            return
        third = s / 3.0
        # Center hole through X
        holes.append((x, y + third, z + third, s, third, third))
        # 4 edge holes
        # along Y direction at center Z
        # along Z direction at center Y
        # Plus the cross pattern - for Menger sponge cross-section
        # The cross-section pattern: center + 4 edges
        # Actually for proper Menger viewed from X: it's the 2D Sierpinski carpet pattern

        # Recurse into 8 sub-cubes (excluding center cross in YZ from X view)
        # For proper Menger sponge, we recurse on sub-cubes that aren't removed
        for i in range(3):
            for j in range(3):
                for k in range(3):
                    # Count how many coords are at center (1)
                    center_count = (i == 1) + (j == 1) + (k == 1)
                    if center_count >= 2:
                        continue  # this sub-cube is removed
                    recurse(x + i*third, y + j*third, z + k*third, third, level - 1)

    # Build holes by tracking removed sub-cubes
    removed = []
    def find_removed(x, y, z, s, level):
        if level == 0:
            return
        third = s / 3.0
        for i in range(3):
            for j in range(3):
                for k in range(3):
                    center_count = (i == 1) + (j == 1) + (k == 1)
                    nx, ny, nz = x + i*third, y + j*third, z + k*third
                    if center_count >= 2:
                        removed.append((nx, ny, nz, third))
                    else:
                        find_removed(nx, ny, nz, third, level - 1)

    find_removed(origin[0], origin[1], origin[2], size, levels)
    return removed

